// import { Link, NavLink } from 'react-router-dom';
import { useTable } from "react-table";

// Пример данных для таблицы
const data = [
  { firstName: "Иван", lastName: "Иванов", age: 28 },
  { firstName: "Мария", lastName: "Петрова", age: 34 },
  { firstName: "Павел", lastName: "Сидоров", age: 22 }
];

// Конфигурация колонок таблицы
const columns = [
  {
    Header: "Имя",
    accessor: "firstName" // поле из объекта data
  },
  {
    Header: "Фамилия",
    accessor: "lastName"
  },
  {
    Header: "Возраст",
    accessor: "age"
  }
];


function Road() {
    // return(
    // <div>
    //     <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
    //         <div className="container-fluid py-2">
    //             <Link className="navbar-brand fs-3 fw-bold" to="/">roads_admin</Link>
    //         </div>
    //         <div className="container-fluid bg-dark py-2">
    //             <div className="navbar-nav flex-row">
    //                 <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/" end> Главная </NavLink>
    //                 <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads" end> Дороги </NavLink>
    //                 <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/sings" end> Дорожные знаки </NavLink>
    //                 <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to="/roads/sings" end> Знаки на дорогах </NavLink>
    //             </div>
    //         </div>
    //     </nav>
    //     <h1>Дороги.</h1>

    //     <div>

    //     </div>
    // </div>
    // );
    // Используем хук useTable для инициализации таблицы
    const tableInstance = useTable({ columns, data });

    // Деструктурируем нужные методы и данные для отрисовки
    const {
      getTableProps,
      getTableBodyProps,
      headerGroups,
      rows,
      prepareRow
    } = tableInstance;

    // Рендерим таблицу
    return (
      <table {...getTableProps()}>
        <thead>
          {headerGroups.map(headerGroup => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map(column => (
                <th {...column.getHeaderProps()}>{column.render('Header')}</th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map(row => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map(cell => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    );
}

export default Road;
